select 
from public.biz_counselor_qualification

    deleted = '0'
    and id = #{id}
    and user_id = #{userId}

        and qualification_name like concat('%', #{qualificationName}, '%')


        and issuing_authority like concat('%', #{issuingAuthority}, '%')

    and cert_no = #{certNo}
    and verify_status = #{verifyStatus}

order by create_time desc

select count(1)
from public.biz_counselor_qualification

    deleted = '0'
    and id = #{id}
    and user_id = #{userId}

        and qualification_name like concat('%', #{qualificationName}, '%')


        and issuing_authority like concat('%', #{issuingAuthority}, '%')

    and cert_no = #{certNo}
    and verify_status = #{verifyStatus}

mapper.update:
update public.biz_counselor_qualification
set verify_status = #{verifyStatus},
    update_time = #{updateTime}
where id = #{id}
  and deleted = '0'

update public.biz_counselor_qualification
set deleted = '1',
    update_time = #{updateTime}
where id = #{id}
  and deleted = '0'
